fn remove(&mut self, entity: Entity) -> Option<T> {
let dense_idx = self.sparse[entity.id()];
if dense_idx == EMPTY { return None; }

pre.code:
// 1. Invalidate sparse target
self.sparse[entity.id()] = EMPTY;
let last_idx = self.dense.len() - 1;

if dense_idx != last_idx {
    // 2. Move last element to hole
    self.dense.swap(dense_idx, last_idx);
    self.entities.swap(dense_idx, last_idx);

    // 3. Fix back-pointer for moved element
    let moved_entity = self.entities[dense_idx];
    self.sparse[moved_entity.id()] = dense_idx;
}

// 4. Shrink arrays
self.entities.pop();
self.dense.pop() // Returns Option&lt;T&gt;
